// Generate a simple blur data URL for placeholder images
export function generateBlurDataURL(width = 10, height = 10): string {
  // Create a simple gradient blur effect
  const svg = `
      <svg width="${width}" height="${height}" xmlns="http://www.w3.org/2000/svg">
        <defs>
          <linearGradient id="grad" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" style="stop-color:#6366f1;stop-opacity:0.8" />
            <stop offset="50%" style="stop-color:#8b5cf6;stop-opacity:0.6" />
            <stop offset="100%" style="stop-color:#06b6d4;stop-opacity:0.4" />
          </linearGradient>
        </defs>
        <rect width="100%" height="100%" fill="url(#grad)" />
        <rect width="100%" height="100%" fill="url(#grad)" opacity="0.5" />
      </svg>
    `;

  const base64 = Buffer.from(svg).toString("base64");
  return `data:image/svg+xml;base64,${base64}`;
}

// Specific blur data URLs for different image types
export const blurDataUrls = {
  avatar: generateBlurDataURL(120, 120),
  photo: generateBlurDataURL(600, 400),
  member: generateBlurDataURL(200, 200),
  default: generateBlurDataURL(100, 100),
};

// Alternative: Simple colored blur data URLs
export const simpleBlurDataUrls = {
  avatar:
    "data:image/jpeg;base64,",
  photo:
    "data:image/jpeg;base64,",
  member:
    "data:image/jpeg;base64,",
};
